(window.webpackJsonp=window.webpackJsonp||[]).push([[635],{613:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">s</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">t</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">maxCost</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> equalSubstring = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">s, t, maxCost</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> cost=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;s.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> codeS=s.charCodeAt(i)<span class=\\"hljs-number\\">-97</span>\\n    <span class=\\"hljs-keyword\\">let</span> codeT=t.charCodeAt(i)<span class=\\"hljs-number\\">-97</span>\\n    cost.push(<span class=\\"hljs-built_in\\">Math</span>.abs(codeS-codeT))\\n  }\\n  <span class=\\"hljs-comment\\">// console.log(cost)</span>\\n\\n  <span class=\\"hljs-keyword\\">let</span> needCost=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> start=<span class=\\"hljs-number\\">0</span>,end=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">while</span>(end&lt;s.length){\\n    needCost+=cost[end]\\n    <span class=\\"hljs-keyword\\">while</span>(needCost&gt;maxCost){\\n      needCost-=cost[start]\\n      start++\\n    }\\n    end++\\n    res=<span class=\\"hljs-built_in\\">Math</span>.max(res,end-start)\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"get-equal-substrings-within-budget","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e24\u4e2a\u957f\u5ea6\u76f8\u540c\u7684\u5b57\u7b26\u4e32\uff0c<code>s</code> \u548c <code>t</code>\u3002</p>\\n\\n<p>\u5c06 <code>s</code>\xa0\u4e2d\u7684\u7b2c\xa0<code>i</code>\xa0\u4e2a\u5b57\u7b26\u53d8\u5230\xa0<code>t</code>\xa0\u4e2d\u7684\u7b2c <code>i</code> \u4e2a\u5b57\u7b26\u9700\u8981\xa0<code>|s[i] - t[i]|</code>\xa0\u7684\u5f00\u9500\uff08\u5f00\u9500\u53ef\u80fd\u4e3a 0\uff09\uff0c\u4e5f\u5c31\u662f\u4e24\u4e2a\u5b57\u7b26\u7684 ASCII \u7801\u503c\u7684\u5dee\u7684\u7edd\u5bf9\u503c\u3002</p>\\n\\n<p>\u7528\u4e8e\u53d8\u66f4\u5b57\u7b26\u4e32\u7684\u6700\u5927\u9884\u7b97\u662f\xa0<code>maxCost</code>\u3002\u5728\u8f6c\u5316\u5b57\u7b26\u4e32\u65f6\uff0c\u603b\u5f00\u9500\u5e94\u5f53\u5c0f\u4e8e\u7b49\u4e8e\u8be5\u9884\u7b97\uff0c\u8fd9\u4e5f\u610f\u5473\u7740\u5b57\u7b26\u4e32\u7684\u8f6c\u5316\u53ef\u80fd\u662f\u4e0d\u5b8c\u5168\u7684\u3002</p>\\n\\n<p>\u5982\u679c\u4f60\u53ef\u4ee5\u5c06 <code>s</code> \u7684\u5b50\u5b57\u7b26\u4e32\u8f6c\u5316\u4e3a\u5b83\u5728 <code>t</code> \u4e2d\u5bf9\u5e94\u7684\u5b50\u5b57\u7b26\u4e32\uff0c\u5219\u8fd4\u56de\u53ef\u4ee5\u8f6c\u5316\u7684\u6700\u5927\u957f\u5ea6\u3002</p>\\n\\n<p>\u5982\u679c <code>s</code> \u4e2d\u6ca1\u6709\u5b50\u5b57\u7b26\u4e32\u53ef\u4ee5\u8f6c\u5316\u6210 <code>t</code> \u4e2d\u5bf9\u5e94\u7684\u5b50\u5b57\u7b26\u4e32\uff0c\u5219\u8fd4\u56de <code>0</code>\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>s = \\"abcd\\", t = \\"bcdf\\", maxCost = 3\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>s<strong> </strong>\u4e2d\u7684<strong> </strong>\\"abc\\" \u53ef\u4ee5\u53d8\u4e3a \\"bcd\\"\u3002\u5f00\u9500\u4e3a 3\uff0c\u6240\u4ee5\u6700\u5927\u957f\u5ea6\u4e3a 3\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>s = \\"abcd\\", t = \\"cdef\\", maxCost = 3\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>s \u4e2d\u7684\u4efb\u4e00\u5b57\u7b26\u8981\u60f3\u53d8\u6210 t \u4e2d\u5bf9\u5e94\u7684\u5b57\u7b26\uff0c\u5176\u5f00\u9500\u90fd\u662f 2\u3002\u56e0\u6b64\uff0c\u6700\u5927\u957f\u5ea6\u4e3a<code> 1\u3002</code>\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>s = \\"abcd\\", t = \\"acde\\", maxCost = 0\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>a -> a, cost = 0\uff0c\u5b57\u7b26\u4e32\u672a\u53d1\u751f\u53d8\u5316\uff0c\u6240\u4ee5\u6700\u5927\u957f\u5ea6\u4e3a 1\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= s.length, t.length <= 10^5</code></li>\\n\\t<li><code>0 <= maxCost <= 10^6</code></li>\\n\\t<li><code>s</code> \u548c\xa0<code>t</code>\xa0\u90fd\u53ea\u542b\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u3002</li>\\n</ul>\\n","title":"1208. \u5c3d\u53ef\u80fd\u4f7f\u5b57\u7b26\u4e32\u76f8\u7b49","relatedTags":["\u6570\u7ec4","Sliding Window"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1208"}')}}]);